#include <iostream>#include <vector>using namespace std; int cnt = 0;int vis[60];vector<int> ans[60];vector<int> tmp;  void dfs(int dep,int n){    if(dep > n){        if(cnt < n){            cnt++;            for(auto v : tmp){                ans[cnt].push_back(v);            }                  }         return;    }        for(int i = 1;i <= n;i++){        if(!vis[i]){            if(dep >= 3){                if(tmp[dep - 3] + tmp[dep - 2] == i){                    continue;                }            }                        vis[i] = true;            tmp.push_back(i);            dfs(dep + 1,n);            tmp.pop_back();            vis[i] = false;        }    }} void solve(){    cnt = 0;        int n;    cin >> n;        for(int i = 1;i <= n;i++) ans[i].clear();        dfs(1,n);      for(int i = 1;i <= n;i++){        for(auto v2 : ans[i]){            cout << v2 << " ";        }        cout << "\n";    }} int main(){    int t;    cin >> t;        while(t--){        solve();    }        return 0;}